// BTDataTable types — organisms/data_table

/// Cell content type within a data table.
enum BTTableCellType {
  text,
  button,
  doubleButton,
  checkbox,
  radio,
  option,
  field,
  dropdown,
  multipleSelection,
  badge,
  toggle,
  number,
}

/// Visual variant of the data table.
enum BTDataTableVariant {
  /// Default — white row background, white header background.
  defaultVariant,

  /// Secondary — header uses brand.primarySubtle.
  secondary,

  /// No fill — transparent background.
  noFill,
}

/// Sort direction for a sortable column.
enum BTDataTableSortDirection { asc, desc, none }

/// A selectable option inside a cell (dropdown / option cells).
class BTDataTableOption {
  const BTDataTableOption({required this.label, required this.value});

  final String label;
  final String value;
}

/// A tag rendered inside a multiple-selection table cell.
class BTDataTableTag {
  const BTDataTableTag({required this.label, this.id});

  final String label;
  final String? id;
}

/// The content model for a single table cell.
///
/// [type] controls how the cell is rendered.
/// Not all fields apply to every type — unused fields are silently ignored.
class BTDataTableCell {
  const BTDataTableCell({
    this.type = BTTableCellType.text,
    this.value,
    this.label,
    this.badgeLabel,
    this.options = const [],
    this.tags = const [],
    this.checked = false,
    this.selected = false,
    this.disabled = false,
  });

  final BTTableCellType type;

  /// Primary value — used by text, number, field, dropdown (selected key).
  final dynamic value;

  /// Display label — used by button, badge.
  final String? label;

  /// Badge label text (overrides [label] for badge cells).
  final String? badgeLabel;

  /// Options list for option / dropdown cells.
  final List<BTDataTableOption> options;

  /// Tags list for multiple-selection cells.
  final List<BTDataTableTag> tags;

  /// Checked state for checkbox / toggle cells.
  final bool checked;

  /// Selected state for radio cells.
  final bool selected;

  /// Disabled state — suppresses interaction.
  final bool disabled;
}

/// Column definition for the data table.
class BTDataTableColumn {
  const BTDataTableColumn({
    required this.key,
    required this.label,
    this.width,
    this.fill = false,
    this.sortable = true,
    this.sortDirection = BTDataTableSortDirection.none,
    this.headerType = 'title',
    this.expander = false,
    this.align = BTDataTableColumnAlign.start,
  });

  /// Unique key matching [BTDataTableRow.cells] map keys.
  final String key;

  /// Header label text (displayed uppercase).
  final String label;

  /// Fixed column width in logical pixels. Ignored when [fill] is true.
  final double? width;

  /// When true, column expands to fill remaining space.
  final bool fill;

  /// Shows a sort indicator in the header.
  final bool sortable;

  /// Current sort direction. [BTDataTableSortDirection.none] shows no arrow.
  final BTDataTableSortDirection sortDirection;

  /// Header cell type: 'title' | 'checkbox-title' | 'title-dropdown'.
  final String headerType;

  /// Renders the tree expand/collapse arrow in this column.
  final bool expander;

  /// Cell content alignment.
  final BTDataTableColumnAlign align;
}

/// Cell content alignment.
enum BTDataTableColumnAlign { start, center, end }

/// A single data row in the table.
class BTDataTableRow {
  const BTDataTableRow({
    required this.id,
    required this.cells,
    this.children,
  });

  /// Unique row identifier.
  final String id;

  /// Cell content keyed by [BTDataTableColumn.key].
  /// Values may be [BTDataTableCell] or plain [String]/[num]/[bool].
  final Map<String, dynamic> cells;

  /// Nested child rows for tree display.
  final List<BTDataTableRow>? children;
}

// ── Payload types ─────────────────────────────────────────────────────────────

/// Payload emitted by [BTDataTable.onAction].
class BTTableActionPayload {
  const BTTableActionPayload({
    required this.action,
    this.rowId,
    this.columnKey,
  });

  /// Action identifier: 'filter' | 'download' | 'upload' | 'create' |
  /// 'check-all' | 'check-row' | 'sort'.
  final String action;

  final String? rowId;
  final String? columnKey;
}

/// Payload emitted by [BTDataTable.onCellChange].
class BTDataTableCellChangePayload {
  const BTDataTableCellChangePayload({
    required this.rowId,
    required this.columnKey,
    required this.cell,
  });

  final String rowId;
  final String columnKey;
  final BTDataTableCell cell;
}

/// Payload emitted by [BTDataTable.onSortChanged].
class BTSortPayload {
  const BTSortPayload({
    required this.columnKey,
    required this.direction,
  });

  final String columnKey;
  final BTDataTableSortDirection direction;
}

/// BTDataTable — compact data table organism.
///
/// Supports flat and tree-structured rows, multi-column sorting, row selection
/// with tri-state header checkbox, filter tags, search, and pagination.
///
/// All colors use `context.btColor.*` — reactive to light/dark theme.
///
/// ## Usage — flat table:
/// ```dart
/// BTDataTable(
///   title: 'Users',
///   columns: const [
///     BTDataTableColumn(key: 'name', label: 'Name', fill: true),
///     BTDataTableColumn(key: 'status', label: 'Status', width: 120),
///   ],
///   rows: _rows,
///   hasCheckbox: true,
///   selectedRows: _selected,
///   onSelectedRowsChanged: (ids) => setState(() => _selected = ids),
///   onCellChange: (p) => print('${p.rowId} / ${p.columnKey}'),
/// )
/// ```
///
/// ## Usage — tree table:
/// ```dart
/// BTDataTable(
///   columns: treeColumns,
///   rows: treeRows,
///   expandedKeys: _expandedKeys,
///   onExpandedKeysChanged: (keys) => setState(() => _expandedKeys = keys),
///   showPagination: false,
/// )
/// ```
library;

import 'dart:math' show max, min;

import 'package:btech_tokens/btech_tokens.dart';
import '../button/button.types.dart';
import '../button/button.widget.dart';
import '../button-link/button_link.widget.dart';
import '../dropdown-list/dropdown_list.types.dart';
import '../hint/hint.dart';
import '../tag/tag.widget.dart';
import '../dropdown/dropdown.widget.dart';
import '../input-search/input_search.widget.dart';
import '../pagination/pagination.widget.dart';
import 'package:btech_ui/src/components/organisms/data_table/bt_data_table.types.dart';
import 'package:btech_ui/src/components/organisms/data_table/internal/bt_table_row.dart';
import 'package:btech_ui/src/components/organisms/data_table/internal/bt_table_title.dart';
import 'package:flutter/material.dart';

/// Compact data table organism. See file header for usage examples.
class BTDataTable extends StatefulWidget {
  const BTDataTable({
    this.title = 'Table Title',
    this.columns = const [],
    this.rows = const [],
    this.variant = BTDataTableVariant.defaultVariant,
    this.showToolbar = true,
    this.showSearch = true,
    this.showFilter = true,
    this.showPagination = true,
    this.searchValue = '',
    this.rowsPerPage = 10,
    this.rowsPerPageOptions = const [10, 20, 50],
    this.currentPage = 1,
    this.totalPages = 5,
    this.filters = const [],
    this.maxVisibleFilters = 4,
    this.expandedKeys = const {},
    this.maxHeight,
    this.fixedHeader = false,
    this.hasCheckbox = false,
    this.fixedLeft = 0,
    this.fixedRight = 0,
    this.headerMinHeight = 32,
    this.rowMinHeight = 68,
    this.selectedRows = const [],
    this.toolbarActions,
    this.onSearchValueChanged,
    this.onSearchSubmit,
    this.onPageChange,
    this.onRowsChange,
    this.onAction,
    this.onCellChange,
    this.onRemoveFilter,
    this.onRemoveAllFilters,
    this.onExpandedKeysChanged,
    this.onSortChanged,
    this.onSelectedRowsChanged,
    super.key,
  });

  final String title;
  final List<BTDataTableColumn> columns;
  final List<BTDataTableRow> rows;
  final BTDataTableVariant variant;

  final bool showToolbar;
  final bool showSearch;
  final bool showFilter;
  final bool showPagination;

  final String searchValue;
  final int rowsPerPage;
  final List<int> rowsPerPageOptions;
  final int currentPage;
  final int totalPages;

  /// Filter tag labels shown below the toolbar.
  final List<String> filters;

  /// Maximum filter tags to show before "+ N more".
  final int maxVisibleFilters;

  /// Map of row id → expanded state for tree rows.
  final Map<String, bool> expandedKeys;

  /// When set, the body area is capped at this height with internal scrolling.
  /// `null` = auto height.
  final double? maxHeight;

  /// Keeps the header visible while the body scrolls vertically when
  /// [maxHeight] is set.
  final bool fixedHeader;

  final bool hasCheckbox;

  /// Number of columns to pin from the left. Checkbox counts as one column
  /// when [hasCheckbox] is true, matching the web DataTable API.
  final int fixedLeft;

  /// Number of data columns to pin from the right, matching the web API.
  final int fixedRight;

  /// Minimum header height. Use a compact value (e.g. 32) for text-only tables.
  final double headerMinHeight;

  /// Minimum body row height. Use a compact value (e.g. 32) for text-only tables.
  final double rowMinHeight;

  final List<String> selectedRows;

  /// Optional widget slot rendered in the toolbar actions area.
  /// When provided, replaces the default Download/Upload/Create buttons.
  final Widget? toolbarActions;

  // Callbacks
  final ValueChanged<String>? onSearchValueChanged;
  final ValueChanged<String>? onSearchSubmit;
  final ValueChanged<int>? onPageChange;
  final ValueChanged<int>? onRowsChange;
  final ValueChanged<BTTableActionPayload>? onAction;
  final ValueChanged<BTDataTableCellChangePayload>? onCellChange;
  final ValueChanged<String>? onRemoveFilter;
  final VoidCallback? onRemoveAllFilters;
  final ValueChanged<Map<String, bool>>? onExpandedKeysChanged;
  final ValueChanged<BTSortPayload>? onSortChanged;
  final ValueChanged<List<String>>? onSelectedRowsChanged;

  @override
  State<BTDataTable> createState() => _BTDataTableState();
}

class _BTDataTableState extends State<BTDataTable> {
  // ── Scroll controllers ─────────────────────────────────────────────────────

  late final ValueNotifier<double> _hScrollOffset;

  /// Drives vertical scroll when [maxHeight] is set.
  late final ScrollController _vScrollCtrl;

  @override
  void initState() {
    super.initState();
    _hScrollOffset = ValueNotifier<double>(0);
    _vScrollCtrl = ScrollController();
  }

  @override
  void dispose() {
    _hScrollOffset.dispose();
    _vScrollCtrl.dispose();
    super.dispose();
  }

  // ── Column widths ──────────────────────────────────────────────────────────

  /// Per-column auto-fit width cache — measured from header label + all cell
  /// content. Recomputed when rows/columns change.
  Map<String, double>? _autoWidthCache;
  int _autoWidthCacheKey = -1;

  /// Hash that invalidates the auto-width cache. Includes `expandedKeys` so
  /// expander columns recompute when tree rows expand/collapse — the visible
  /// depth changes, so the column needs to grow or shrink accordingly.
  int get _columnCacheKey => Object.hash(
        widget.columns.length,
        widget.rows.length,
        widget.hasCheckbox,
        // Use ONLY the truthy keys count + their joined hash so equal expansion
        // states map to equal keys regardless of map iteration order.
        Object.hashAll(
          widget.expandedKeys.entries
              .where((e) => e.value)
              .map((e) => e.key)
              .toList()
            ..sort(),
        ),
      );

  /// Computes pixel widths for each column given a container width.
  ///
  /// Resolution priority per column:
  /// 1. `col.fill == true` → splits remaining space equally
  /// 2. `col.width != null` → fixed
  /// 3. Otherwise → auto-fit to content (header + all cells, 8px padding)
  List<double> _computeColumnWidths(double containerWidth) {
    final checkboxW = widget.hasCheckbox ? kCheckboxWidth : 0.0;
    final available = containerWidth - checkboxW;

    // Invalidate auto-width cache when rows/columns change
    if (_autoWidthCache == null || _autoWidthCacheKey != _columnCacheKey) {
      _autoWidthCache = {
        for (final col in widget.columns)
          if (col.width == null && !col.fill) col.key: _measureColumnWidth(col),
      };
      _autoWidthCacheKey = _columnCacheKey;
    }

    double fixed = 0;
    int fillCount = 0;
    for (final col in widget.columns) {
      if (col.fill) {
        fillCount++;
      } else if (col.width != null) {
        fixed += col.width!;
      } else {
        fixed += _autoWidthCache![col.key] ?? 120.0;
      }
    }

    final fillWidth = fillCount > 0
        ? ((available - fixed) / fillCount).clamp(80.0, 400.0)
        : 0.0;

    return widget.columns.map((col) {
      if (col.fill) return fillWidth;
      if (col.width != null) return col.width!;
      return _autoWidthCache![col.key] ?? 120.0;
    }).toList();
  }

  /// Measures the natural width a column needs to fit its header + all cells.
  /// Returns measured width clamped to [kColumnMinWidth..kColumnMaxWidth] with
  /// 16px (8px×2) horizontal padding.
  ///
  /// Min-width 135px matches Figma D-DataTable spec (node 2373-11580).
  double _measureColumnWidth(BTDataTableColumn col) {
    const padding = 16.0; // 8px left + 8px right
    const minWidth = 135.0; // Figma spec — default column min-width
    // Expander columns can need much more width due to depth-based indent;
    // give them headroom up to ~640px, others stay capped at 400.
    final maxWidth = col.expander ? 640.0 : 400.0;

    double measureText(String text, double size, FontWeight weight) {
      if (text.isEmpty) return 0;
      final painter = TextPainter(
        text: TextSpan(
          text: text,
          style: TextStyle(fontSize: size, fontWeight: weight, height: 1.4),
        ),
        textDirection: TextDirection.ltr,
        maxLines: 1,
      )..layout();
      return painter.width;
    }

    // Header label (uppercase, 11/600)
    double maxContentW = measureText(
      col.label.toUpperCase(),
      11,
      FontWeight.w600,
    );
    if (col.sortable) maxContentW += 20; // sort icon + gap

    // Measure VISIBLE rows only — depth tracked so expander column accounts
    // for tree indent (matches `_buildDataCell` in bt_table_row.dart):
    //   _expanderIndent = 4 + (depth-1) * 24   for depth >= 1
    //   + 16 (chevron / leaf placeholder)
    //   + 4 (gap before content)
    //
    // Children are only traversed when their parent is expanded — collapsed
    // subtrees don't contribute to the column width. This means the column
    // dynamically grows/shrinks as the user expands/collapses rows.
    void traverse(List<BTDataTableRow> rows, int depth) {
      for (final row in rows) {
        final raw = row.cells[col.key];
        final BTDataTableCell? cell = raw is BTDataTableCell ? raw : null;
        double w = 0;

        if (cell != null) {
          switch (cell.type) {
            case BTTableCellType.text:
            case BTTableCellType.number:
              w = measureText(
                cell.value?.toString() ?? '',
                12,
                FontWeight.w500,
              );
              break;
            case BTTableCellType.badge:
              w = measureText(
                    cell.badgeLabel ?? cell.label ?? 'Badge',
                    11,
                    FontWeight.w500,
                  ) +
                  24; // badge pill padding
              break;
            case BTTableCellType.button:
              w = measureText(cell.label ?? 'Label', 12, FontWeight.w500) + 24;
              break;
            case BTTableCellType.doubleButton:
              w = 72; // two 32px iconOnly buttons + 4 gap + padding
              break;
            case BTTableCellType.checkbox:
            case BTTableCellType.radio:
            case BTTableCellType.toggle:
              w = 32;
              break;
            case BTTableCellType.option:
              w = 180; // two radios + labels
              break;
            case BTTableCellType.field:
            case BTTableCellType.dropdown:
              w = 160; // input min width
              break;
            case BTTableCellType.multipleSelection:
              w = 220;
              break;
          }
        } else if (raw != null) {
          w = measureText(raw.toString(), 12, FontWeight.w500);
        }

        // Tree expander indent — accumulates with depth.
        // depth >= 1 → indent = 4 + (depth-1)*24; depth=0 (defensive) → 0.
        if (col.expander) {
          final indent = depth >= 1 ? 4.0 + (depth - 1) * 24.0 : 0.0;
          w += indent + 16 /* chevron/leaf */ + 4 /* gap before content */;
        }

        if (w > maxContentW) maxContentW = w;

        // Only recurse into children if the row is currently expanded.
        // Collapsed rows hide their subtree, so they shouldn't count.
        final isExpanded = widget.expandedKeys[row.id] == true;
        if (isExpanded && row.children != null) {
          traverse(row.children!, depth + 1);
        }
      }
    }

    // BTTableRow renders top-level rows with depth=1 (matches its _buildRows call)
    traverse(widget.rows, 1);

    return (maxContentW + padding).clamp(minWidth, maxWidth);
  }

  // ── Check-all logic ────────────────────────────────────────────────────────

  /// Header tri-state — derived from each top-level row's recursive check state,
  /// NOT from flat IDs. A parent row counts as "checked" when all its leaf
  /// descendants are selected, even if the parent's own ID isn't in selectedRows.
  /// Mirrors web computeHeaderCheckState logic.
  bool? get _checkAllState {
    if (widget.rows.isEmpty) return false;
    final sel = widget.selectedRows;
    final states = widget.rows.map((r) => _rowCheckState(r, sel)).toList();
    if (states.every((s) => s == true)) return true;
    if (states.every((s) => s == false)) return false;
    return null; // indeterminate
  }

  /// Recursive tri-state for a single row — mirrors BTTableRow._computeParentCheckState.
  /// Leaf row: true iff its id is in `sel`.
  /// Parent row: derived from children's states (all true → true, all false → false,
  /// mixed → null/indeterminate).
  static bool? _rowCheckState(BTDataTableRow row, List<String> sel) {
    if (row.children == null || row.children!.isEmpty) {
      return sel.contains(row.id);
    }
    final childStates =
        row.children!.map((c) => _rowCheckState(c, sel)).toList();
    if (childStates.every((s) => s == true)) return true;
    if (childStates.every((s) => s == false)) return false;
    return null;
  }

  static List<String> _allRowIds(List<BTDataTableRow> rows) {
    final result = <String>[];
    for (final r in rows) {
      result.add(r.id);
      if (r.children != null) {
        result.addAll(_allRowIds(r.children!));
      }
    }
    return result;
  }

  void _handleCheckAll() {
    final allIds = _allRowIds(widget.rows);
    final current = _checkAllState;
    final List<String> next;
    if (current == true) {
      next = [];
    } else {
      next = allIds;
    }
    widget.onSelectedRowsChanged?.call(next);
    widget.onAction?.call(
      const BTTableActionPayload(action: 'check-all'),
    );
  }

  void _handleCheckRow(String rowId) {
    // Find the clicked row and cascade to all its descendants — matches web logic.
    final target = _findRow(widget.rows, rowId);
    final affectedIds = target != null ? _allRowIds([target]) : [rowId];

    final sel = List<String>.from(widget.selectedRows);
    final allSelected = affectedIds.every(sel.contains);

    if (allSelected) {
      sel.removeWhere(affectedIds.contains);
    } else {
      for (final id in affectedIds) {
        if (!sel.contains(id)) sel.add(id);
      }
    }

    widget.onSelectedRowsChanged?.call(sel);
    widget.onAction?.call(
      BTTableActionPayload(action: 'check-row', rowId: rowId),
    );
  }

  static BTDataTableRow? _findRow(List<BTDataTableRow> rows, String id) {
    for (final r in rows) {
      if (r.id == id) return r;
      if (r.children != null) {
        final found = _findRow(r.children!, id);
        if (found != null) return found;
      }
    }
    return null;
  }

  static List<_VisibleDataTableRow> _flattenVisibleRows(
    List<BTDataTableRow> rows,
    Map<String, bool> expandedKeys, [
    int depth = 1,
  ]) {
    final visible = <_VisibleDataTableRow>[];
    for (final row in rows) {
      visible.add(_VisibleDataTableRow(row: row, depth: depth));
      final children = row.children;
      if (children != null &&
          children.isNotEmpty &&
          expandedKeys[row.id] == true) {
        visible.addAll(_flattenVisibleRows(children, expandedKeys, depth + 1));
      }
    }
    return visible;
  }

  // ── Sort ───────────────────────────────────────────────────────────────────

  void _handleSort(String key, BTDataTableSortDirection current) {
    final next = switch (current) {
      BTDataTableSortDirection.none => BTDataTableSortDirection.asc,
      BTDataTableSortDirection.asc => BTDataTableSortDirection.desc,
      BTDataTableSortDirection.desc => BTDataTableSortDirection.none,
    };
    widget.onSortChanged?.call(BTSortPayload(columnKey: key, direction: next));
  }

  // ── Build ──────────────────────────────────────────────────────────────────

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;

    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        // ── Toolbar ────────────────────────────────────────────────────────
        if (widget.showToolbar) _buildToolbar(context, c),

        // ── Filter tags ────────────────────────────────────────────────────
        if (widget.showFilter && widget.filters.isNotEmpty)
          _buildFilters(context, c),

        // ── Table — LayoutBuilder gives the actual container width
        //   synchronously per frame. No floor, no 2-frame delay, no overflow
        //   when container < previously-cached size.
        LayoutBuilder(
          builder: (context, constraints) {
            final viewportWidth = constraints.maxWidth;
            final colWidths = _computeColumnWidths(viewportWidth);
            return _buildTableFrame(context, c, colWidths, viewportWidth);
          },
        ),

        // ── Pagination ─────────────────────────────────────────────────────
        if (widget.showPagination) _buildPagination(context, c),
      ],
    );
  }

  // ── Toolbar ────────────────────────────────────────────────────────────────

  /// Header layout (Figma 4001-62044):
  ///   Row 1: Title
  ///   Row 2: Full-width search input
  ///   Row 3: Filter button + toolbar actions (Download/Upload/Create)
  Widget _buildToolbar(BuildContext context, BTColorTheme c) {
    final activeFilterCount = widget.filters.length;
    final filterButton = BTButton.iconOnly(
      icon: Icon(
        Icons.filter_alt,
        size: 16,
        color: c.text.primary,
      ),
      variant: BTButtonVariant.secondaryWhite,
      size: BTButtonSize.md,
      rightIcon: activeFilterCount > 0
          ? BTHint(count: activeFilterCount, size: BTHintSize.sm)
          : null,
      onPressed: () => widget.onAction?.call(
        const BTTableActionPayload(action: 'filter'),
      ),
    );

    final defaultActions = Row(
      mainAxisSize: MainAxisSize.min,
      children: [
        BTButton(
          label: 'Download',
          leftIcon: Icon(
            Icons.download_rounded,
            size: 16,
            color: c.text.secondary,
          ),
          variant: BTButtonVariant.secondaryWhite,
          size: BTButtonSize.md,
          onPressed: () => widget.onAction?.call(
            const BTTableActionPayload(action: 'download'),
          ),
        ),
        const SizedBox(width: 8.0),
        BTButton(
          label: 'Upload',
          leftIcon: Icon(
            Icons.upload_rounded,
            size: 16,
            color: c.text.secondary,
          ),
          variant: BTButtonVariant.secondaryWhite,
          size: BTButtonSize.md,
          onPressed: () => widget.onAction?.call(
            const BTTableActionPayload(action: 'upload'),
          ),
        ),
        const SizedBox(width: 8.0),
        BTButton(
          label: '+ Create',
          variant: BTButtonVariant.primary,
          size: BTButtonSize.md,
          onPressed: () => widget.onAction?.call(
            const BTTableActionPayload(action: 'create'),
          ),
        ),
      ],
    );

    final actionContent = Row(
      mainAxisSize: MainAxisSize.min,
      children: [
        if (widget.showFilter) ...[
          filterButton,
          const SizedBox(width: 8.0),
        ],
        widget.toolbarActions ?? defaultActions,
      ],
    );

    return Padding(
      padding: const EdgeInsets.only(bottom: 8.0),
      child: Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          // ── Row 1: Title ─────────────────────────────────────────────────
          Padding(
            padding: const EdgeInsets.only(bottom: 8.0),
            child: Text(
              widget.title,
              style: TextStyle(
                fontFamily: BTTypography.fontFamily,
                fontSize: 14.0,
                fontWeight: FontWeight.w600,
                color: c.text.primary,
              ),
            ),
          ),

          // ── Row 2: Full-width search ─────────────────────────────────────
          if (widget.showSearch)
            Padding(
              padding: const EdgeInsets.only(bottom: 8.0),
              child: BTInputSearch(
                value: widget.searchValue,
                placeholder: 'Search',
                onChanged: widget.onSearchValueChanged,
                onSearch: widget.onSearchSubmit,
              ),
            ),

          // ── Row 3: Filter + action buttons (right-aligned) ───────────────
          LayoutBuilder(
            builder: (context, constraints) {
              final isCompact = constraints.maxWidth < 520;

              if (isCompact) {
                return SingleChildScrollView(
                  scrollDirection: Axis.horizontal,
                  physics: const ClampingScrollPhysics(),
                  child: actionContent,
                );
              }

              return Row(
                crossAxisAlignment: CrossAxisAlignment.center,
                children: [
                  const Spacer(),
                  actionContent,
                ],
              );
            },
          ),
        ],
      ),
    );
  }

  // ── Filter tags ────────────────────────────────────────────────────────────

  Widget _buildFilters(BuildContext context, BTColorTheme c) {
    final visible = widget.filters.take(widget.maxVisibleFilters).toList();
    final hidden = widget.filters.skip(widget.maxVisibleFilters).toList();

    return Container(
      margin: const EdgeInsets.only(bottom: 8.0),
      child: Wrap(
        spacing: 8.0,
        runSpacing: 4.0,
        crossAxisAlignment: WrapCrossAlignment.center,
        children: [
          for (final tag in visible)
            BTTag(
              label: tag,
              onRemove: () => widget.onRemoveFilter?.call(tag),
            ),
          // "+N" overflow → BTDropdown listing hidden filter tags. Each row
          // shows an × icon on the right (space-between via removable: true)
          // signalling that tapping the row will remove that filter.
          if (hidden.isNotEmpty)
            BTDropdown<String>(
              items: [
                for (final tag in hidden)
                  BTDropdownItem<String>(
                    value: tag,
                    label: tag,
                    removable: true,
                  ),
              ],
              onSelect: (tag) {
                if (tag != null) widget.onRemoveFilter?.call(tag);
              },
              trigger: ({required toggle, required isOpen}) => GestureDetector(
                onTap: toggle,
                behavior: HitTestBehavior.opaque,
                child: BTTag(label: '+${hidden.length}'),
              ),
            ),
          if (widget.filters.isNotEmpty)
            BTButtonLink.secondary(
              label: 'Remove All',
              onPressed: widget.onRemoveAllFilters,
            ),
        ],
      ),
    );
  }

  // ── Table frame ────────────────────────────────────────────────────────────

  Widget _buildTableFrame(
    BuildContext context,
    BTColorTheme c,
    List<double> colWidths,
    double containerWidth,
  ) {
    final bg = switch (widget.variant) {
      BTDataTableVariant.noFill => Colors.transparent,
      _ => c.bg.primary,
    };

    // ── Responsive degrade: when the container is too narrow to fit
    // (left fixed + right fixed + a minimal middle viewport), disable sticky
    // columns entirely so the whole table scrolls horizontally. Prevents the
    // RenderFlex overflow stripes on phones in portrait orientation.
    const borderInset = 2.0;
    const minMiddleViewport = 80.0; // smallest "scrollable middle" we'll allow

    int effectiveLeft = widget.fixedLeft.clamp(0, widget.columns.length);
    int effectiveRight =
        widget.fixedRight.clamp(0, widget.columns.length - effectiveLeft);

    final checkboxW = widget.hasCheckbox ? kCheckboxWidth : 0.0;
    double leftColsWTest =
        colWidths.sublist(0, effectiveLeft).fold(0.0, (a, b) => a + b);
    double rightColsWTest = effectiveRight > 0
        ? colWidths
            .sublist(widget.columns.length - effectiveRight)
            .fold(0.0, (a, b) => a + b)
        : 0.0;

    final canFitSticky = (checkboxW +
            leftColsWTest +
            rightColsWTest +
            borderInset +
            minMiddleViewport) <=
        containerWidth;
    if (!canFitSticky) {
      effectiveLeft = 0;
      effectiveRight = 0;
    }

    // Column split indices (using possibly-zeroed effective counts)
    final leftCount = effectiveLeft;
    final rightCount = effectiveRight;
    final middleEnd = widget.columns.length - rightCount;

    // Pixel widths
    final leftColsW =
        colWidths.sublist(0, leftCount).fold(0.0, (a, b) => a + b);
    final rightColsW = rightCount > 0
        ? colWidths.sublist(middleEnd).fold(0.0, (a, b) => a + b)
        : 0.0;
    final leftW = checkboxW + leftColsW;
    final middleColsW =
        colWidths.sublist(leftCount, middleEnd).fold(0.0, (a, b) => a + b);

    final availableMiddle = max(
      0.0,
      containerWidth - leftW - rightColsW - borderInset,
    );

    // Table fits container → visibleMiddleW = middleColsW (don't stretch),
    // total table width = sum of all column widths.
    // Table overflows → visibleMiddleW = available viewport (scroll horizontally).
    final fits = middleColsW <= availableMiddle;
    final visibleMiddleW = fits ? middleColsW : availableMiddle;
    final middleW = max(middleColsW, visibleMiddleW);

    final tableBody = _buildTableBody(
      context,
      c,
      colWidths,
      leftCount,
      rightCount,
      middleW,
      visibleMiddleW,
    );

    // Horizontal-scroll shadow indicators (hoisted from per-row to here).
    // One ValueListenableBuilder for the entire table → spans the full
    // table height (header + all data rows) via Positioned.fill.
    final hasLeftSection = widget.hasCheckbox || leftCount > 0;
    final hasRightSection = rightCount > 0;
    final maxHScroll =
        middleW > visibleMiddleW ? middleW - visibleMiddleW : 0.0;

    final tableFrame = Container(
      decoration: BoxDecoration(
        color: bg,
        border: Border.all(color: c.border.primary),
        borderRadius: BorderRadius.circular(8.0),
      ),
      child: ClipRRect(
        borderRadius: BorderRadius.circular(8.0),
        child: Stack(
          children: [
            tableBody,
            if (hasLeftSection || hasRightSection)
              Positioned.fill(
                child: IgnorePointer(
                  child: ValueListenableBuilder<double>(
                    valueListenable: _hScrollOffset,
                    builder: (ctx, offset, _) {
                      final showLeading = hasLeftSection && offset > 0.5;
                      final showTrailing = hasRightSection &&
                          maxHScroll > 0.5 &&
                          offset < maxHScroll - 0.5;
                      if (!showLeading && !showTrailing) {
                        return const SizedBox.shrink();
                      }
                      return _BTTableShadowOverlay(
                        leftWidth: leftW,
                        rightWidth: rightColsW,
                        showLeading: showLeading,
                        showTrailing: showTrailing,
                      );
                    },
                  ),
                ),
              ),
          ],
        ),
      ),
    );

    // When content fits container, align table to the start so it sizes to
    // content (instead of stretching to full container width via Column.stretch).
    if (fits) {
      final totalTableW = leftW + visibleMiddleW + rightColsW + borderInset;
      return Align(
        alignment: Alignment.centerLeft,
        child: SizedBox(width: totalTableW, child: tableFrame),
      );
    }
    return tableFrame;
  }

  // ── Table body (header + rows) ─────────────────────────────────────────────

  Widget _buildTableBody(
    BuildContext context,
    BTColorTheme c,
    List<double> colWidths,
    int leftCount,
    int rightCount,
    double middleW,
    double visibleMiddleW,
  ) {
    final header = BTTableTitle(
      columns: widget.columns,
      variant: widget.variant,
      hasCheckbox: widget.hasCheckbox,
      checkAllState: _checkAllState,
      columnWidths: colWidths,
      fixedLeft: leftCount,
      fixedRight: rightCount,
      hScrollOffset: _hScrollOffset,
      onHorizontalOffsetChanged: (offset) => _hScrollOffset.value = offset,
      middleW: middleW,
      visibleMiddleW: visibleMiddleW,
      headerMinHeight: widget.headerMinHeight,
      onCheckAll: widget.hasCheckbox ? _handleCheckAll : null,
      onSort: _handleSort,
    );

    final divider = Container(height: 1.0, color: c.border.primary);
    final visibleRows = _flattenVisibleRows(widget.rows, widget.expandedKeys);
    final maxHorizontalOffset =
        middleW > visibleMiddleW ? middleW - visibleMiddleW : 0.0;
    final estimatedBodyHeight = visibleRows.isEmpty
        ? 0.0
        : visibleRows.length * widget.rowMinHeight +
            max(0, visibleRows.length - 1).toDouble();
    final estimatedHeaderHeight = widget.headerMinHeight + 1.0;

    Widget buildRowAt(int index) {
      final visibleRow = visibleRows[index];
      return BTTableRow(
        key: ValueKey(visibleRow.row.id),
        row: visibleRow.row,
        columns: widget.columns,
        columnWidths: colWidths,
        depth: visibleRow.depth,
        variant: widget.variant,
        hasCheckbox: widget.hasCheckbox,
        isSelected: widget.selectedRows.contains(visibleRow.row.id),
        expandedKeys: widget.expandedKeys,
        selectedRows: widget.selectedRows,
        fixedLeft: leftCount,
        fixedRight: rightCount,
        hScrollOffset: _hScrollOffset,
        onHorizontalOffsetChanged: (offset) {
          _hScrollOffset.value = offset;
        },
        middleW: middleW,
        visibleMiddleW: visibleMiddleW,
        rowMinHeight: widget.rowMinHeight,
        showBottomDivider: index != visibleRows.length - 1,
        onCheckRow: widget.hasCheckbox ? _handleCheckRow : null,
        onCellChange: widget.onCellChange,
        onExpandedKeysChanged: widget.onExpandedKeysChanged,
      );
    }

    final rows = Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: List.generate(visibleRows.length, buildRowAt),
    );

    final isRtl = Directionality.of(context) == TextDirection.rtl;
    final dragSign = isRtl ? 1.0 : -1.0;

    final bodyContent = GestureDetector(
      behavior: HitTestBehavior.translucent,
      onHorizontalDragUpdate: maxHorizontalOffset <= 0
          ? null
          : (details) {
              final next = (_hScrollOffset.value + dragSign * details.delta.dx)
                  .clamp(0.0, maxHorizontalOffset);
              if ((next - _hScrollOffset.value).abs() >= 0.5) {
                _hScrollOffset.value = next;
              }
            },
      child: rows,
    );

    final lazyBodyContent = GestureDetector(
      behavior: HitTestBehavior.translucent,
      onHorizontalDragUpdate: maxHorizontalOffset <= 0
          ? null
          : (details) {
              final next = (_hScrollOffset.value + dragSign * details.delta.dx)
                  .clamp(0.0, maxHorizontalOffset);
              if ((next - _hScrollOffset.value).abs() >= 0.5) {
                _hScrollOffset.value = next;
              }
            },
      child: ListView.builder(
        controller: _vScrollCtrl,
        physics: const ClampingScrollPhysics(),
        itemCount: visibleRows.length,
        cacheExtent: widget.rowMinHeight * 8,
        itemBuilder: (context, index) => buildRowAt(index),
      ),
    );

    if (widget.maxHeight == null) {
      return Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [header, divider, bodyContent],
      );
    }

    if (widget.fixedHeader) {
      final bodyHeight = min(
        widget.maxHeight!,
        estimatedBodyHeight <= 0 ? widget.rowMinHeight : estimatedBodyHeight,
      );

      return Column(
        mainAxisSize: MainAxisSize.min,
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          header,
          divider,
          SizedBox(
            height: bodyHeight,
            child: lazyBodyContent,
          ),
        ],
      );
    }

    final tableHeight = min(
      widget.maxHeight!,
      estimatedHeaderHeight +
          (estimatedBodyHeight <= 0
              ? widget.rowMinHeight
              : estimatedBodyHeight),
    );

    return SizedBox(
      height: tableHeight,
      child: SingleChildScrollView(
        controller: _vScrollCtrl,
        physics: const ClampingScrollPhysics(),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [header, divider, bodyContent],
        ),
      ),
    );
  }

  // ── Pagination ─────────────────────────────────────────────────────────────

  Widget _buildPagination(BuildContext context, BTColorTheme c) {
    return Container(
      margin: const EdgeInsets.only(top: 8.0),
      child: BTPagination.display(
        currentPage: widget.currentPage,
        totalPages: widget.totalPages,
        totalCount: widget.rows.length,
        rowsPerPage: widget.rowsPerPage,
        rowsPerPageOptions: widget.rowsPerPageOptions,
        onPageChange: widget.onPageChange ?? (_) {},
        onRowsChange: widget.onRowsChange,
      ),
    );
  }
}

class _VisibleDataTableRow {
  const _VisibleDataTableRow({
    required this.row,
    required this.depth,
  });

  final BTDataTableRow row;
  final int depth;
}

/// Table-level horizontal-scroll shadow overlay. Renders 18px linear-gradient
/// bands at the inner edge of the left/right sticky sections to indicate that
/// more content exists past the pinned column. Hoisted from per-row to here
/// so the gradient spans the full table height (header + all data rows) and
/// only ONE ValueListenableBuilder rebuilds on each horizontal scroll tick.
class _BTTableShadowOverlay extends StatelessWidget {
  const _BTTableShadowOverlay({
    required this.leftWidth,
    required this.rightWidth,
    required this.showLeading,
    required this.showTrailing,
  });

  final double leftWidth;
  final double rightWidth;
  final bool showLeading;
  final bool showTrailing;

  @override
  Widget build(BuildContext context) {
    const shadowWidth = 18.0;

    return Stack(
      clipBehavior: Clip.none,
      children: [
        if (showLeading)
          PositionedDirectional(
            top: 0,
            bottom: 0,
            start: leftWidth,
            width: shadowWidth,
            child: const DecoratedBox(
              decoration: BoxDecoration(
                gradient: LinearGradient(
                  begin: AlignmentDirectional.centerStart,
                  end: AlignmentDirectional.centerEnd,
                  colors: [
                    Color(0x14000000),
                    Color(0x0A000000),
                    Color(0x00000000),
                  ],
                ),
              ),
            ),
          ),
        if (showTrailing)
          PositionedDirectional(
            top: 0,
            bottom: 0,
            end: rightWidth,
            width: shadowWidth,
            child: const DecoratedBox(
              decoration: BoxDecoration(
                gradient: LinearGradient(
                  begin: AlignmentDirectional.centerEnd,
                  end: AlignmentDirectional.centerStart,
                  colors: [
                    Color(0x14000000),
                    Color(0x0A000000),
                    Color(0x00000000),
                  ],
                ),
              ),
            ),
          ),
      ],
    );
  }
}

import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';

class BTSyncedHorizontalViewport extends StatefulWidget {
  const BTSyncedHorizontalViewport({
    required this.offsetListenable,
    required this.onOffsetChanged,
    required this.viewportWidth,
    required this.contentWidth,
    required this.child,
    this.interactive = true,
    super.key,
  });

  final ValueListenable<double> offsetListenable;
  final ValueChanged<double> onOffsetChanged;
  final double viewportWidth;
  final double contentWidth;
  final Widget child;
  final bool interactive;

  @override
  State<BTSyncedHorizontalViewport> createState() =>
      _BTSyncedHorizontalViewportState();
}

class _BTSyncedHorizontalViewportState
    extends State<BTSyncedHorizontalViewport> {
  ScrollController? _controller;
  bool _isSyncing = false;

  @override
  void initState() {
    super.initState();
    _attachController();
  }

  @override
  void didUpdateWidget(covariant BTSyncedHorizontalViewport oldWidget) {
    super.didUpdateWidget(oldWidget);
    if (oldWidget.offsetListenable != widget.offsetListenable) {
      oldWidget.offsetListenable.removeListener(_syncFromExternalOffset);
      widget.offsetListenable.addListener(_syncFromExternalOffset);
    }
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (mounted) _syncFromExternalOffset();
    });
  }

  @override
  void dispose() {
    _detachController();
    super.dispose();
  }

  void _attachController() {
    if (_controller != null) return;
    final controller = ScrollController();
    controller.addListener(_handleScroll);
    widget.offsetListenable.addListener(_syncFromExternalOffset);
    _controller = controller;
  }

  void _detachController() {
    final controller = _controller;
    if (controller == null) return;
    widget.offsetListenable.removeListener(_syncFromExternalOffset);
    controller.removeListener(_handleScroll);
    controller.dispose();
    _controller = null;
  }

  void _handleScroll() {
    final controller = _controller;
    if (_isSyncing || controller == null || !controller.hasClients) return;
    widget.onOffsetChanged(controller.offset);
  }

  void _syncFromExternalOffset() {
    final controller = _controller;
    if (controller == null || !controller.hasClients) return;
    final target = widget.offsetListenable.value.clamp(
      0.0,
      controller.position.maxScrollExtent,
    );
    if ((controller.offset - target).abs() < 0.5) return;
    _isSyncing = true;
    controller.jumpTo(target);
    _isSyncing = false;
  }

  @override
  Widget build(BuildContext context) {
    final viewportWidth = widget.viewportWidth.clamp(0.0, double.infinity);
    final contentWidth = widget.contentWidth < viewportWidth
        ? viewportWidth
        : widget.contentWidth;

    return SizedBox(
      width: viewportWidth,
      child: SingleChildScrollView(
        controller: _controller,
        scrollDirection: Axis.horizontal,
        physics: widget.interactive
            ? const ClampingScrollPhysics()
            : const NeverScrollableScrollPhysics(),
        child: SizedBox(
          width: contentWidth,
          child: widget.child,
        ),
      ),
    );
  }
}

