// ─── Inline SVG icons matching the web double-button design ──────────────────
const _kEditSvg =
    '''
<svg viewBox="0 0 16 16" xmlns="http://www.w3.org/2000/svg">
  <path d="M3 8.67V12.5H6.83L12.13 7.2L8.3 3.37L3 8.67Z
           M13.03 6.3L13.75 5.58C14.08 5.25 14.08 4.73 13.75 4.4
           L11.6 2.25C11.27 1.92 10.75 1.92 10.42 2.25L9.7 2.97L13.03 6.3Z"
        fill="black"/>
</svg>''';

const _kListSvg =
    '''
<svg viewBox="0 0 16 16" xmlns="http://www.w3.org/2000/svg">
  <path d="M3.5 4.5H12.5V5.83H3.5V4.5Z
           M3.5 7.33H12.5V8.67H3.5V7.33Z
           M3.5 10.17H12.5V11.5H3.5V10.17Z"
        fill="black"/>
</svg>''';

/// Renders the content of a single data cell.
///
/// All interactive cells delegate to `onCellChange` — the parent table
/// owns mutable state; this widget is stateless for everything except the
/// text-field controller which must persist across rebuilds.
class BTTableItem extends StatefulWidget {
  const BTTableItem({
    required this.column,
    required this.rowId,
    required this.cell,
    this.onCellChange,
    super.key,
  });

  final BTDataTableColumn column;
  final String rowId;
  final BTDataTableCell cell;
  final void Function(BTDataTableCellChangePayload)? onCellChange;

  @override
  State<BTTableItem> createState() => _BTTableItemState();
}

class _BTTableItemState extends State<BTTableItem> {
  // Field controller persists across rebuilds so text is not lost.
  late final TextEditingController _fieldCtrl;

  @override
  void initState() {
    super.initState();
    _fieldCtrl = TextEditingController(
      text: widget.cell.value?.toString() ?? '',
    );
  }

  @override
  void dispose() {
    _fieldCtrl.dispose();
    super.dispose();
  }

  void _emit(BTDataTableCell updated) {
    widget.onCellChange?.call(
      BTDataTableCellChangePayload(
        rowId: widget.rowId,
        columnKey: widget.column.key,
        cell: updated,
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    final cell = widget.cell;
    final align = switch (widget.column.align) {
      BTDataTableColumnAlign.center => Alignment.center,
      BTDataTableColumnAlign.end => Alignment.centerRight,
      BTDataTableColumnAlign.start => Alignment.centerLeft,
    };

    // Sections wrapped in IntrinsicHeight auto-expand to tallest content.
    // No fixed height — field/dropdown cells (BTInput = 50dp) size naturally.
    return Align(
      alignment: align,
      child: switch (cell.type) {
        BTTableCellType.text => _padded(_text(c, cell)),
        BTTableCellType.number => _padded(_number(c, cell)),
        BTTableCellType.button => _padded(_button(cell)),
        BTTableCellType.doubleButton => _padded(_doubleButton(c, cell)),
        BTTableCellType.checkbox => _padded(_checkbox(cell)),
        BTTableCellType.radio => _padded(_radio(cell)),
        BTTableCellType.option => _padded(_BTTableOption(
            cell: cell,
            onChanged: (v) => _emit(
              BTDataTableCell(
                type: BTTableCellType.option,
                value: v,
                options: cell.options,
                disabled: cell.disabled,
              ),
            ),
          )),
        BTTableCellType.field => _fieldCell(cell),
        BTTableCellType.dropdown => _dropdownCell(cell),
        BTTableCellType.multipleSelection => _multipleSelectionCell(cell),
        BTTableCellType.badge => _padded(_badge(cell)),
        BTTableCellType.toggle => _padded(_toggle(cell)),
      },
    );
  }

  // ── Helpers ─────────────────────────────────────────────────────────────────

  Widget _padded(Widget child) => child;

  // ── text ────────────────────────────────────────────────────────────────────

  Widget _text(BTColorTheme c, BTDataTableCell cell) => Text(
        cell.value?.toString() ?? '',
        style: TextStyle(
          fontFamily: BTTypography.fontFamily,
          fontSize: 12,
          fontWeight: FontWeight.w500,
          height: 16 / 12,
          color: c.text.primary,
        ),
        overflow: TextOverflow.ellipsis,
      );

  // ── number ──────────────────────────────────────────────────────────────────

  Widget _number(BTColorTheme c, BTDataTableCell cell) => Text(
        cell.value?.toString() ?? '',
        textAlign: TextAlign.end,
        style: TextStyle(
          fontFamily: BTTypography.fontFamily,
          fontSize: 12,
          fontWeight: FontWeight.w500,
          height: 16 / 12,
          color: c.text.primary,
        ),
      );

  // ── button ──────────────────────────────────────────────────────────────────

  /// Renders a single [BTButton] (primary variant, sm size).
  Widget _button(BTDataTableCell cell) => BTButton(
        label: cell.label ?? 'Label',
        variant: BTButtonVariant.primary,
        size: BTButtonSize.sm,
        onPressed: cell.disabled ? null : () => _emit(cell),
      );

  // ── double-button ────────────────────────────────────────────────────────────

  /// Two [BTButton.iconOnly] widgets side-by-side — an edit (primary) and a
  /// menu/list (secondary-light) action.  Icons match the web SVG paths.
  Widget _doubleButton(BTColorTheme c, BTDataTableCell cell) => Row(
        mainAxisSize: MainAxisSize.min,
        children: [
          // Primary — edit action
          BTButton.iconOnly(
            icon: SvgPicture.string(
              _kEditSvg,
              width: 14,
              height: 14,
              colorFilter: ColorFilter.mode(c.text.inverse, BlendMode.srcIn),
            ),
            variant: BTButtonVariant.primary,
            size: BTButtonSize.sm,
            onPressed: cell.disabled
                ? null
                : () => _emit(
                      BTDataTableCell(
                        type: BTTableCellType.doubleButton,
                        value: 'edit',
                        label: cell.label,
                        disabled: cell.disabled,
                      ),
                    ),
          ),
          const SizedBox(width: 4),
          // Secondary — list/menu action
          BTButton.iconOnly(
            icon: SvgPicture.string(
              _kListSvg,
              width: 14,
              height: 14,
              colorFilter: ColorFilter.mode(c.text.secondary, BlendMode.srcIn),
            ),
            variant: BTButtonVariant.secondaryLight,
            size: BTButtonSize.sm,
            onPressed: cell.disabled
                ? null
                : () => _emit(
                      BTDataTableCell(
                        type: BTTableCellType.doubleButton,
                        value: 'list',
                        label: cell.label,
                        disabled: cell.disabled,
                      ),
                    ),
          ),
        ],
      );

  // ── checkbox ─────────────────────────────────────────────────────────────────

  Widget _checkbox(BTDataTableCell cell) => BTCheckbox(
        checked: cell.checked,
        disabled: cell.disabled,
        onChanged: cell.disabled
            ? null
            : (_) => _emit(
                  BTDataTableCell(
                    type: BTTableCellType.checkbox,
                    checked: !cell.checked,
                    disabled: cell.disabled,
                  ),
                ),
      );

  // ── radio ─────────────────────────────────────────────────────────────────────

  Widget _radio(BTDataTableCell cell) => BTRadioButton<bool>(
        groupValue: cell.selected,
        value: true,
        disabled: cell.disabled,
        // onChanged is required non-nullable; the disabled flag suppresses taps.
        onChanged: (_) => _emit(
          BTDataTableCell(
            type: BTTableCellType.radio,
            selected: true,
            disabled: cell.disabled,
          ),
        ),
      );

  // ── field ─────────────────────────────────────────────────────────────────────

  /// Full-width text input using [BTInput] (default variant).
  Widget _fieldCell(BTDataTableCell cell) => BTInput(
        controller: _fieldCtrl,
        label: 'Title',
        disabled: cell.disabled,
        onChanged: (v) => _emit(
          BTDataTableCell(
            type: BTTableCellType.field,
            value: v,
            disabled: cell.disabled,
          ),
        ),
      );

  // ── dropdown ──────────────────────────────────────────────────────────────────

  /// Inline [BTInputDropdown] for single-value selection.
  Widget _dropdownCell(BTDataTableCell cell) {
    final opts = cell.options.isEmpty ? _kDefaultDropdownOptions : cell.options;
    return BTInputDropdown<String>(
      label: cell.label ?? 'Title',
      value: cell.value?.toString(),
      disabled: cell.disabled,
      items: opts
          .map(
            (o) => BTDropdownItem<String>(
              value: o.value,
              label: o.label,
              disabled: cell.disabled,
            ),
          )
          .toList(),
      onChanged: (v) => _emit(
        BTDataTableCell(
          type: BTTableCellType.dropdown,
          value: v,
          options: cell.options,
          disabled: cell.disabled,
        ),
      ),
    );
  }

  static const _kDefaultDropdownOptions = [
    BTDataTableOption(label: 'Title', value: 'title'),
    BTDataTableOption(label: 'Label', value: 'label'),
    BTDataTableOption(label: 'Draft', value: 'draft'),
  ];

  // ── multiple-selection ────────────────────────────────────────────────────────

  /// Tag-based multi-value input using [BTInputMultipleField].
  Widget _multipleSelectionCell(BTDataTableCell cell) =>
      BTInputMultipleField<String>(
        label: 'Title',
        type: BTInputMultipleFieldType.scroll,
        disabled: cell.disabled,
        items: cell.options
            .map((o) => BTDropdownItem<String>(value: o.value, label: o.label))
            .toList(),
        onChanged: (tags) => _emit(
          BTDataTableCell(
            type: BTTableCellType.multipleSelection,
            options: tags
                .map(
                  (t) => BTDataTableOption(
                    label: t.label,
                    value: t.effectiveId,
                  ),
                )
                .toList(),
            disabled: cell.disabled,
          ),
        ),
      );

  // ── badge ─────────────────────────────────────────────────────────────────────

  /// [BTBadge] — variant is driven by the badge label value.
  Widget _badge(BTDataTableCell cell) {
    final label = cell.badgeLabel ?? cell.label ?? 'Badge';
    // Map common label values to badge variants (mirrors web showcase logic).
    final variant = switch (label.toLowerCase()) {
      'selected' || 'success' || 'approved' => BTBadgeVariant.success,
      'waiting' || 'pending' || 'review' => BTBadgeVariant.waiting,
      'reject' || 'rejected' || 'error' => BTBadgeVariant.reject,
      _ => BTBadgeVariant.neutral,
    };
    return BTBadge(label: label, variant: variant);
  }

  // ── toggle ────────────────────────────────────────────────────────────────────

  Widget _toggle(BTDataTableCell cell) => BTSwitchField(
        value: cell.checked,
        size: BTSwitchFieldSize.sm,
        disabled: cell.disabled,
        onChanged: cell.disabled
            ? null
            : (v) => _emit(
                  BTDataTableCell(
                    type: BTTableCellType.toggle,
                    checked: v,
                    disabled: cell.disabled,
                  ),
                ),
      );
}

// ─── Internal: option cell ────────────────────────────────────────────────────

/// Option cell — renders a row of [BTRadioButton] widgets, one per option.
///
/// Matches Figma node 2349-2726 ("Type=Option"): two radio buttons side by
/// side with their labels, separated by a 16dp gap.
///
/// Used exclusively by [BTTableItem] for [BTTableCellType.option] cells.
class _BTTableOption extends StatelessWidget {
  const _BTTableOption({
    required this.cell,
    required this.onChanged,
  });

  final BTDataTableCell cell;
  final void Function(String value) onChanged;

  static const _kDefaultOptions = [
    BTDataTableOption(label: 'Label A', value: 'a'),
    BTDataTableOption(label: 'Label B', value: 'b'),
  ];

  @override
  Widget build(BuildContext context) {
    final opts = cell.options.isEmpty ? _kDefaultOptions : cell.options;
    final selected = cell.value?.toString() ?? '';

    return Wrap(
      spacing: 12,
      runSpacing: 4,
      children: [
        for (final opt in opts)
          BTRadioButton<String>(
            groupValue: selected,
            value: opt.value,
            label: opt.label,
            disabled: cell.disabled,
            // onChanged is required non-nullable; disabled flag suppresses taps.
            onChanged: onChanged,
          ),
      ],
    );
  }
}

// internal — data row widget for BTDataTable (not exported)
// Supports a single visible tree row. The parent table flattens expanded rows.
// ignore_for_file: prefer_int_literals

import 'package:btech_tokens/btech_tokens.dart';
import '../../checkbox/checkbox.widget.dart';
import 'package:btech_ui/src/components/organisms/data_table/bt_data_table.types.dart';
import 'package:btech_ui/src/components/organisms/data_table/internal/bt_synced_horizontal_viewport.dart';
import 'package:btech_ui/src/components/organisms/data_table/internal/bt_table_item.dart';
import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';

/// Default mixed-content header row height.
const double kRowHeight = 52.0;

/// Default mixed-content data row minimum height.
const double kDataRowControlHeight = 68.0;

/// Checkbox column width.
const double kCheckboxWidth = 40.0;

/// Renders a single data row.
///
/// Left (checkbox + fixedLeft cols) and right (fixedRight cols) sections are
/// pinned. The middle section scrolls horizontally with a shared offset so all
/// rows stay in sync.
class BTTableRow extends StatefulWidget {
  const BTTableRow({
    required this.row,
    required this.columns,
    required this.columnWidths,
    required this.depth,
    required this.variant,
    required this.hasCheckbox,
    required this.isSelected,
    required this.expandedKeys,
    required this.selectedRows,
    required this.fixedLeft,
    required this.fixedRight,
    required this.hScrollOffset,
    required this.onHorizontalOffsetChanged,
    required this.middleW,
    required this.visibleMiddleW,
    required this.rowMinHeight,
    required this.showBottomDivider,
    this.onCheckRow,
    this.onCellChange,
    this.onExpandedKeysChanged,
    super.key,
  });

  final BTDataTableRow row;
  final List<BTDataTableColumn> columns;
  final List<double> columnWidths;
  final int depth;
  final BTDataTableVariant variant;
  final bool hasCheckbox;
  final bool isSelected;
  final Map<String, bool> expandedKeys;
  final List<String> selectedRows;

  /// Number of data columns pinned from the left (does not count checkbox).
  final int fixedLeft;

  /// Number of data columns pinned from the right.
  final int fixedRight;

  /// Shared horizontal scroll controller — offset drives middle translation.
  final ValueListenable<double> hScrollOffset;
  final ValueChanged<double> onHorizontalOffsetChanged;

  /// Total pixel width of all middle (scrollable) columns combined.
  final double middleW;

  /// Visible (viewport) width of the middle section — used as SizedBox width
  /// so the ClipRect clips correctly without needing Expanded.
  final double visibleMiddleW;

  final double rowMinHeight;

  final bool showBottomDivider;

  final void Function(String rowId)? onCheckRow;
  final void Function(BTDataTableCellChangePayload)? onCellChange;
  final void Function(Map<String, bool>)? onExpandedKeysChanged;

  @override
  State<BTTableRow> createState() => _BTTableRowState();
}

class _BTTableRowState extends State<BTTableRow> {
  bool _isHovered = false;

  bool get _enableHover => switch (defaultTargetPlatform) {
        TargetPlatform.macOS ||
        TargetPlatform.windows ||
        TargetPlatform.linux =>
          true,
        _ => false,
      };

  bool get _hasChildren =>
      widget.row.children != null && widget.row.children!.isNotEmpty;

  bool get _isExpanded => widget.expandedKeys[widget.row.id] ?? false;

  /// Tri-state checkbox for rows with children.
  bool? get _checkState {
    if (!widget.hasCheckbox) return false;
    if (!_hasChildren) {
      return widget.selectedRows.contains(widget.row.id);
    }
    return _computeParentCheckState(widget.row, widget.selectedRows);
  }

  static bool? _computeParentCheckState(
    BTDataTableRow row,
    List<String> selected,
  ) {
    if (row.children == null || row.children!.isEmpty) {
      return selected.contains(row.id);
    }
    final childStates = row.children!
        .map((c) => _computeParentCheckState(c, selected))
        .toList();
    if (childStates.every((s) => s == true)) return true;
    if (childStates.every((s) => s == false)) return false;
    return null; // indeterminate
  }

  void _toggleExpand() {
    final next = Map<String, bool>.from(widget.expandedKeys);
    next[widget.row.id] = !_isExpanded;
    widget.onExpandedKeysChanged?.call(next);
  }

  // ── Row background ─────────────────────────────────────────────────────────

  Color _rowBg(BTColorTheme c) {
    // Parent rows: highlight when ALL children are selected (checkState == true).
    // Leaf rows: highlight when row id is in selectedRows.
    final isSelected = _hasChildren ? _checkState == true : widget.isSelected;
    if (isSelected) return c.brand.primarySubtle;
    if (_isHovered) return c.bg.subtle;
    return switch (widget.variant) {
      BTDataTableVariant.noFill => Colors.transparent,
      _ => _depthColor(c, widget.depth),
    };
  }

  static Color _depthColor(BTColorTheme c, int depth) {
    return switch (depth) {
      1 => c.bg.primary,
      2 => const Color(0xFFF9F9FA), // lGrey 50
      3 => const Color(0xFFF3F4F5), // lGrey 100
      4 => const Color(0xFFECEEF0), // lGrey 150
      5 => const Color(0xFFE6E8EB), // lGrey 200
      _ => const Color(0xFFDADDE1), // lGrey 300
    };
  }

  // ── Expander indent for tree ───────────────────────────────────────────────

  /// Left indent in the expander column: 4 + (depth-1) * 24 dp, matching BTTree.
  double get _expanderIndent => 4.0 + (widget.depth - 1) * 24.0;

  Widget _wrapHover(Widget child) {
    if (!_enableHover) return child;
    return MouseRegion(
      cursor: SystemMouseCursors.basic,
      onEnter: (_) => setState(() => _isHovered = true),
      onExit: (_) => setState(() => _isHovered = false),
      child: child,
    );
  }

  // ── Section builders ───────────────────────────────────────────────────────

  Widget _buildDataCell(
    BuildContext context,
    BTColorTheme c,
    int colIndex, {
    required bool showLeftDivider,
  }) {
    final col = widget.columns[colIndex];
    final width = widget.columnWidths[colIndex];

    final rawCell = widget.row.cells[col.key];
    final BTDataTableCell cell;
    if (rawCell is BTDataTableCell) {
      cell = rawCell;
    } else if (rawCell != null) {
      cell = BTDataTableCell(
        type: BTTableCellType.text,
        value: rawCell.toString(),
      );
    } else {
      cell = const BTDataTableCell(type: BTTableCellType.text, value: '');
    }

    final align = switch (col.align) {
      BTDataTableColumnAlign.center => MainAxisAlignment.center,
      BTDataTableColumnAlign.end => MainAxisAlignment.end,
      BTDataTableColumnAlign.start => MainAxisAlignment.start,
    };

    // Expander cells are tappable on the whole cell, not just the arrow.
    final isExpanderCell = col.expander && _hasChildren;

    return SizedBox(
        width: width,
        child: GestureDetector(
          onTap: isExpanderCell ? _toggleExpand : null,
          child: Container(
            constraints: BoxConstraints(minHeight: widget.rowMinHeight),
            decoration: BoxDecoration(
              border: showLeftDivider
                  ? BorderDirectional(
                      start: BorderSide(color: c.border.primary))
                  : null,
            ),
            child: Padding(
              padding: const EdgeInsets.all(8),
              child: Row(
                mainAxisAlignment: align,
                crossAxisAlignment: CrossAxisAlignment.center,
                children: [
                  // Expander arrow (only in expander column)
                  if (col.expander && (_hasChildren || widget.depth > 1)) ...[
                    SizedBox(width: _expanderIndent),
                    if (_hasChildren)
                      SizedBox(
                        width: 16.0,
                        height: 16.0,
                        child: AnimatedRotation(
                          turns: _isExpanded ? 0.0 : -0.25,
                          duration: const Duration(milliseconds: 150),
                          child: Icon(
                            Icons.keyboard_arrow_down_rounded,
                            size: 16,
                            color: c.text.secondary,
                          ),
                        ),
                      )
                    else
                      const SizedBox(width: 16.0),
                    const SizedBox(width: 4.0),
                  ],

                  // Cell content — BTTableItem renders raw content, no extra padding.
                  Flexible(
                    child: BTTableItem(
                      column: col,
                      rowId: widget.row.id,
                      cell: cell,
                      onCellChange: widget.onCellChange,
                    ),
                  ),
                ],
              ),
            ),
          ),
        ));
  }

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    final bg = _rowBg(c);

    final leftCount = widget.fixedLeft.clamp(0, widget.columns.length);
    final rightCount =
        widget.fixedRight.clamp(0, widget.columns.length - leftCount);
    final middleEnd = widget.columns.length - rightCount;

    final hasLeftSection = widget.hasCheckbox || leftCount > 0;
    final hasRightSection = rightCount > 0;

    // Pre-compute widths
    final checkboxW = widget.hasCheckbox ? kCheckboxWidth : 0.0;
    final leftColsW =
        widget.columnWidths.sublist(0, leftCount).fold(0.0, (a, b) => a + b);

    Widget? leftSection;
    if (hasLeftSection) {
      leftSection = _wrapHover(
        Container(
          width: checkboxW + leftColsW,
          color: bg,
          constraints: BoxConstraints(minHeight: widget.rowMinHeight),
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.center,
            children: [
              if (widget.hasCheckbox)
                Container(
                  width: kCheckboxWidth,
                  constraints: BoxConstraints(minHeight: widget.rowMinHeight),
                  decoration: BoxDecoration(
                    border: BorderDirectional(
                      end: BorderSide(color: c.border.primary),
                    ),
                  ),
                  child: Center(
                    child: GestureDetector(
                      onTap: () => widget.onCheckRow?.call(widget.row.id),
                      child: BTCheckbox(
                        checked: _checkState == true,
                        indeterminate: _checkState == null,
                        onChanged: (_) =>
                            widget.onCheckRow?.call(widget.row.id),
                      ),
                    ),
                  ),
                ),
              for (var i = 0; i < leftCount; i++)
                _buildDataCell(
                  context,
                  c,
                  i,
                  showLeftDivider: i > 0,
                ),
            ],
          ),
        ),
      );
    }

    final middleScrollable = ColoredBox(
      color: bg,
      child: ConstrainedBox(
        constraints: BoxConstraints(minHeight: widget.rowMinHeight),
        child: BTSyncedHorizontalViewport(
          offsetListenable: widget.hScrollOffset,
          onOffsetChanged: widget.onHorizontalOffsetChanged,
          viewportWidth: widget.visibleMiddleW,
          contentWidth: widget.middleW,
          interactive: false,
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.center,
            children: [
              for (var i = leftCount; i < middleEnd; i++)
                _buildDataCell(
                  context,
                  c,
                  i,
                  showLeftDivider: leftCount > 0 || i > leftCount,
                ),
            ],
          ),
        ),
      ),
    );

    final middleSection = _wrapHover(middleScrollable);

    Widget? rightSection;
    if (hasRightSection) {
      final rightColsW =
          widget.columnWidths.sublist(middleEnd).fold(0.0, (a, b) => a + b);
      rightSection = _wrapHover(
        Container(
          width: rightColsW,
          color: bg,
          constraints: BoxConstraints(minHeight: widget.rowMinHeight),
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.center,
            children: [
              for (var i = middleEnd; i < widget.columns.length; i++)
                _buildDataCell(
                  context,
                  c,
                  i,
                  showLeftDivider: true,
                ),
            ],
          ),
        ),
      );
    }

    final rowContent = Row(
      crossAxisAlignment: CrossAxisAlignment.center,
      children: [
        if (leftSection != null) leftSection,
        middleSection,
        if (rightSection != null) rightSection,
      ],
    );

    final rowWidget = (hasLeftSection || hasRightSection)
        ? rowContent
        : _wrapHover(
            ColoredBox(
              color: bg,
              child: ConstrainedBox(
                constraints: BoxConstraints(minHeight: widget.rowMinHeight),
                child: BTSyncedHorizontalViewport(
                  offsetListenable: widget.hScrollOffset,
                  onOffsetChanged: widget.onHorizontalOffsetChanged,
                  viewportWidth: widget.visibleMiddleW,
                  contentWidth: widget.middleW,
                  interactive: false,
                  child: Row(
                    crossAxisAlignment: CrossAxisAlignment.center,
                    children: [
                      for (var i = leftCount; i < middleEnd; i++)
                        _buildDataCell(
                          context,
                          c,
                          i,
                          showLeftDivider: leftCount > 0 || i > leftCount,
                        ),
                    ],
                  ),
                ),
              ),
            ),
          );

    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.stretch,
      children: [
        rowWidget,
        if (widget.showBottomDivider)
          Container(
            height: 1.0,
            color: c.border.primary,
          ),
      ],
    );
  }
}

// internal — header row for BTDataTable (not exported)
import 'package:btech_tokens/btech_tokens.dart';
import '../../checkbox/checkbox.widget.dart';
import 'package:btech_ui/src/components/organisms/data_table/bt_data_table.types.dart';
import 'package:btech_ui/src/components/organisms/data_table/internal/bt_synced_horizontal_viewport.dart';
import 'package:btech_ui/src/components/organisms/data_table/internal/bt_table_row.dart';
import 'package:flutter/foundation.dart';
import 'package:flutter/material.dart';

/// Renders the sticky header row.
///
/// When [fixedLeft] > 0 or [hasCheckbox] is true, the left section is pinned.
/// When [fixedRight] > 0 the right section is pinned.
/// The middle section scrolls horizontally with the shared table offset.
class BTTableTitle extends StatelessWidget {
  const BTTableTitle({
    required this.columns,
    required this.variant,
    required this.hasCheckbox,
    required this.checkAllState,
    required this.columnWidths,
    required this.fixedLeft,
    required this.fixedRight,
    required this.hScrollOffset,
    required this.onHorizontalOffsetChanged,
    required this.middleW,
    required this.visibleMiddleW,
    required this.headerMinHeight,
    this.onCheckAll,
    this.onSort,
    super.key,
  });

  final List<BTDataTableColumn> columns;
  final BTDataTableVariant variant;
  final bool hasCheckbox;

  /// Tri-state for the header checkbox (all / none / some rows selected).
  final bool? checkAllState; // null = indeterminate, true = all, false = none

  final List<double> columnWidths;

  /// Number of data columns pinned from the left (does not count checkbox).
  final int fixedLeft;

  /// Number of data columns pinned from the right.
  final int fixedRight;

  final ValueListenable<double> hScrollOffset;
  final ValueChanged<double> onHorizontalOffsetChanged;

  /// Total pixel width of all middle (scrollable) columns combined.
  final double middleW;

  /// Visible (viewport) width of the middle section — used as SizedBox width.
  final double visibleMiddleW;

  final double headerMinHeight;

  final VoidCallback? onCheckAll;
  final void Function(String columnKey, BTDataTableSortDirection current)?
      onSort;

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    final headerBg = switch (variant) {
      BTDataTableVariant.secondary => c.brand.primarySubtle,
      BTDataTableVariant.noFill => Colors.transparent,
      BTDataTableVariant.defaultVariant => c.bg.secondary,
    };

    final leftCount = fixedLeft.clamp(0, columns.length);
    final rightCount = fixedRight.clamp(0, columns.length - leftCount);
    final middleStart = leftCount;
    final middleEnd = columns.length - rightCount;

    final leftCols = columns.sublist(0, leftCount);
    final middleCols = columns.sublist(middleStart, middleEnd);
    final rightCols = rightCount > 0
        ? columns.sublist(middleEnd)
        : const <BTDataTableColumn>[];

    final leftWidths = columnWidths.sublist(0, leftCount);
    final middleWidths = columnWidths.sublist(middleStart, middleEnd);
    final rightWidths =
        rightCount > 0 ? columnWidths.sublist(middleEnd) : const <double>[];

    final checkboxW = hasCheckbox ? kCheckboxWidth : 0.0;

    final hasLeftSection = hasCheckbox || leftCount > 0;
    final hasRightSection = rightCount > 0;
    final maxHorizontalOffset =
        middleW > visibleMiddleW ? middleW - visibleMiddleW : 0.0;

    // ── Left cells ─────────────────────────────────────────────────────────────
    // Header height is content-driven (Padding all:8 per cell + IntrinsicHeight on outer Row).
    // headerMinHeight only acts as a floor for short labels.
    Widget? leftWidget;
    if (hasLeftSection) {
      final leftColsW = leftWidths.fold(0.0, (a, b) => a + b);
      leftWidget = Container(
        width: checkboxW + leftColsW,
        color: headerBg,
        child: Row(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            if (hasCheckbox)
              Container(
                width: kCheckboxWidth,
                decoration: BoxDecoration(
                  border: BorderDirectional(
                    end: BorderSide(color: c.border.primary),
                  ),
                ),
                child: Padding(
                  padding: const EdgeInsets.all(8),
                  child: Center(
                    child: IgnorePointer(
                      ignoring: onCheckAll == null,
                      child: GestureDetector(
                        onTap: onCheckAll,
                        child: BTCheckbox(
                          checked: checkAllState == true,
                          indeterminate: checkAllState == null,
                          onChanged: (_) => onCheckAll?.call(),
                        ),
                      ),
                    ),
                  ),
                ),
              ),
            for (var i = 0; i < leftCols.length; i++)
              _BTHeaderCell(
                column: leftCols[i],
                width: leftWidths[i],
                bg: headerBg,
                minHeight: headerMinHeight,
                showLeftDivider: i > 0,
                onSort: onSort,
              ),
          ],
        ),
      );
    }

    final middleScrollable = ColoredBox(
      color: headerBg,
      child: BTSyncedHorizontalViewport(
        offsetListenable: hScrollOffset,
        onOffsetChanged: onHorizontalOffsetChanged,
        viewportWidth: visibleMiddleW,
        contentWidth: middleW,
        child: Row(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            for (var i = 0; i < middleCols.length; i++)
              _BTHeaderCell(
                column: middleCols[i],
                width: middleWidths[i],
                bg: headerBg,
                minHeight: headerMinHeight,
                showLeftDivider: leftCount > 0 || i > 0,
                onSort: onSort,
              ),
          ],
        ),
      ),
    );

    // Shadow indicators for horizontal scroll are rendered at the table-frame
    // level (BTDataTable._buildTableFrame). The header itself doesn't wrap
    // a per-row shadow — that would only show on the header row and skip
    // the data rows below (the bug this fix is patching).
    final middleWidget = middleScrollable;

    Widget? rightWidget;
    if (hasRightSection) {
      final rightColsW = rightWidths.fold(0.0, (a, b) => a + b);
      rightWidget = Container(
        width: rightColsW,
        color: headerBg,
        child: Row(
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            for (var i = 0; i < rightCols.length; i++)
              _BTHeaderCell(
                column: rightCols[i],
                width: rightWidths[i],
                bg: headerBg,
                minHeight: headerMinHeight,
                showLeftDivider: true,
                onSort: onSort,
              ),
          ],
        ),
      );
    }

    // IntrinsicHeight + Row.stretch: header height = tallest cell (driven by
    // header label + 8px padding). All sections share that height per row.
    return IntrinsicHeight(
      child: Row(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          if (leftWidget != null) leftWidget,
          middleWidget,
          if (rightWidget != null) rightWidget,
        ],
      ),
    );
  }
}

class _BTHeaderCell extends StatelessWidget {
  const _BTHeaderCell({
    required this.column,
    required this.width,
    required this.bg,
    required this.minHeight,
    required this.showLeftDivider,
    this.onSort,
  });

  final BTDataTableColumn column;
  final double width;
  final Color bg;
  final double minHeight;
  final bool showLeftDivider;
  final void Function(String key, BTDataTableSortDirection current)? onSort;

  @override
  Widget build(BuildContext context) {
    final c = context.btColor;
    // Sort icon ALWAYS visible (matches web Figma 2373-11580). Tap only fires
    // the callback when the column opts in via `sortable: true`.
    final isSortable = column.sortable && onSort != null;
    final dir = column.sortDirection;

    final labelText = Text(
      column.label.toUpperCase(),
      style: TextStyle(
        fontFamily: BTTypography.fontFamily,
        fontSize: 11.0,
        fontWeight: FontWeight.w600,
        height: 16 / 11,
        color: c.text.secondary,
        letterSpacing: 0.3,
      ),
      overflow: TextOverflow.ellipsis,
    );

    // Header layout: label left, sort icon right — space-between always
    // (matches Figma 2373-11580). `column.align` only affects data cells.
    Widget headerContent = Row(
      mainAxisAlignment: MainAxisAlignment.spaceBetween,
      crossAxisAlignment: CrossAxisAlignment.center,
      children: [
        Expanded(child: labelText),
        const SizedBox(width: 4),
        _SortIcon(direction: dir, color: c.text.secondary),
      ],
    );

    // Wrap in GestureDetector only when sortable — non-sortable still shows
    // the icon but doesn't react to taps.
    if (isSortable) {
      headerContent = MouseRegion(
        cursor: SystemMouseCursors.click,
        child: GestureDetector(
          onTap: () => onSort!(column.key, dir),
          behavior: HitTestBehavior.opaque,
          child: headerContent,
        ),
      );
    }

    return Container(
      width: width,
      constraints: BoxConstraints(minHeight: minHeight),
      decoration: BoxDecoration(
        color: bg,
        border: showLeftDivider
            ? BorderDirectional(start: BorderSide(color: c.border.primary))
            : null,
      ),
      child: Padding(
        padding: const EdgeInsets.all(8),
        child: headerContent,
      ),
    );
  }
}

class _SortIcon extends StatelessWidget {
  const _SortIcon({required this.direction, required this.color});

  final BTDataTableSortDirection direction;
  final Color color;

  @override
  Widget build(BuildContext context) {
    switch (direction) {
      case BTDataTableSortDirection.asc:
        return Icon(Icons.arrow_upward_rounded, size: 12, color: color);
      case BTDataTableSortDirection.desc:
        return Icon(Icons.arrow_downward_rounded, size: 12, color: color);
      case BTDataTableSortDirection.none:
        return Icon(Icons.unfold_more_rounded,
            size: 12, color: color.withOpacity(0.5));
    }
  }
}
